# Streaming RMSE for monitoring in production
class RunningRMSE:
    """Maintains a running RMSE without storing all predictions."""
    def __init__(self):
        self.n = 0
        self.sum_sq_errors = 0.0
        self.sum_abs_errors = 0.0

    def update(self, y_true, y_pred):
        errors = y_true - y_pred
        self.n += len(errors)
        self.sum_sq_errors  += (errors ** 2).sum()
        self.sum_abs_errors += abs(errors).sum()

    @property
    def rmse(self):
        return (self.sum_sq_errors / self.n) ** 0.5 if self.n > 0 else float("nan")

    @property
    def mae(self):
        return self.sum_abs_errors / self.n if self.n > 0 else float("nan")

# Usage in inference loop
tracker = RunningRMSE()
for batch_true, batch_pred in inference_batches:
    tracker.update(batch_true, batch_pred)

print(f"Running MAE:  {tracker.mae:.4f}")
print(f"Running RMSE: {tracker.rmse:.4f}")
